function Login() {
  return (
    <div>
      <h2>Login Page</h2>
      <form>
        <input type="email" placeholder="Email" /><br />
        <input type="password" placeholder="Password" /><br />
        <button type="button">Login</button>
      </form>
    </div>
  );
}

export default Login;
